const items = $input.all();
const results = [];

for (const item of items) {
  const raw = item.json.message || item.json.payload || JSON.stringify(item.json);
  let parsed;
  try {
    parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch (e) {
    parsed = { raw_message: raw };
  }

  const alertData = parsed.data || {};
  const severity = (alertData.severity || 'low').toLowerCase();
  const emoji = { critical: '🔴', high: '🟠', medium: '🟡', low: '🟢' }[severity] || '⚪';

  const discordMessage = emoji + ' SENTINEL ALERT ' + emoji
    + '\n\nType: ' + (alertData.detection_type || 'UNKNOWN')
    + '\nSeverity: ' + severity.toUpperCase()
    + '\nSource: ' + (alertData.src_ip || '?') + ' → ' + (alertData.dst_ip || '?')
    + '\nMessage: ' + (alertData.message || '')
    + '\nTime: ' + (parsed.timestamp || '');

  results.push({
    json: {
      discord_message: discordMessage,
      detection_type: alertData.detection_type,
      severity: severity,
      src_ip: alertData.src_ip,
      dst_ip: alertData.dst_ip,
    }
  });
}

return results;
